```javascript
// ---- Shapes library ----
const SHAPES = {
  Lines: {
    line: { label: 'Line', gen: (w, h) => ShapeFactory.line(0, h/2, w, h/2), dw: 80, dh: 2 },
    arrow: { label: 'Arrow Right', gen: (w, h) => ShapeFactory.arrow(w, h), dw: 100, dh: 50 },
  },
  Rectangles: {
    rect: { label: 'Rectangle', gen: (w, h) => ShapeFactory.rectangle(w, h, 0), dw: 150, dh: 100 },
    roundedRect: { label: 'Rounded Rectangle', gen: (w, h) => ShapeFactory.rectangle(w, h, 8), dw: 150, dh: 100 },
  },
  BasicShapes: {
    ellipse: { label: 'Oval', gen: (w, h) => ShapeFactory.ellipse(w, h), dw: 150, dh: 100 },
    triangle: { label: 'Triangle', gen: (w, h) => ShapeFactory.triangle(w, h), dw: 120, dh: 100 },
    diamond: { label: 'Diamond', gen: (w, h) => ShapeFactory.diamond(w, h), dw: 100, dh: 100 },
  },
  BlockArrows: {
    rightArrow: { label: 'Right Arrow', gen: (w, h) => ShapeFactory.rightArrow(w, h), dw: 150, dh: 80 },
    leftArrow: { label: 'Left Arrow', gen: (w, h) => ShapeFactory.leftArrow(w, h), dw: 150, dh: 80 },
    upDownArrow: { label: 'Up/Down Arrow', gen: (w, h) => ShapeFactory.upDownArrow(w, h), dw: 80, dh: 150 },
  },
  StarsAndBanners: {
    star5: { label: '5-Point Star', gen: (w, h) => ShapeFactory.star(w, h, 5), dw: 100, dh: 100 },
    star8: { label: '8-Point Star', gen: (w, h) => ShapeFactory.star(w, h, 8), dw: 100, dh: 100 },
    banner: { label: 'Banner', gen: (w, h) => ShapeFactory.banner(w, h), dw: 150, dh: 80 },
  },
  Callouts: {
    speechBubble: { label: 'Speech Bubble', gen: (w, h) => ShapeFactory.callout(w, h, 'speech'), dw: 150, dh: 100 },
    thoughtBubble: { label: 'Thought Bubble', gen: (w, h) => ShapeFactory.callout(w, h, 'thought'), dw: 150, dh: 100 },
  },
};

const ShapeFactory = {
  line(x1, y1, x2, y2) {
    return `<svg viewBox="0 0 ${x2} ${y2}" preserveAspectRatio="none"><line x1="${x1}" y1="${y1}" x2="${x2}" y2="${y2}" stroke="#000" stroke-width="2" stroke-linecap="round"/></svg>`;
  },
  rectangle(w, h, rx = 0) {
    return `<svg viewBox="0 0 ${w} ${h}" preserveAspectRatio="none"><rect width="${w}" height="${h}" rx="${rx}" fill="#4472C4" stroke="#000" stroke-width="1.5"/></svg>`;
  },
  ellipse(w, h) {
    const cx = w / 2, cy = h / 2, rx = cx, ry = cy;
    return `<svg viewBox="0 0 ${w} ${h}" preserveAspectRatio="none"><ellipse cx="${cx}" cy="${cy}" rx="${rx}" ry="${ry}" fill="#4472C4" stroke="#000" stroke-width="1.5"/></svg>`;
  },
  triangle(w, h) {
    return `<svg viewBox="0 0 ${w} ${h}" preserveAspectRatio="none"><polygon points="${w/2},0 ${w},${h} 0,${h}" fill="#4472C4" stroke="#000" stroke-width="1.5"/></svg>`;
  },
  diamond(w, h) {
    const cx = w / 2, cy = h / 2;
    return `<svg viewBox="0 0 ${w} ${h}" preserveAspectRatio="none"><polygon points="${cx},0 ${w},${cy} ${cx},${h} 0,${cy}" fill="#4472C4" stroke="#000" stroke-width="1.5"/></svg>`;
  },
  rightArrow(w, h) {
    const arrowHeadW = w * 0.3, arrowHeadH = h * 0.5, bodyW = w - arrowHeadW, bodyH = h * 0.4, topGap = (h - bodyH) / 2;
    return `<svg viewBox="0 0 ${w} ${h}" preserveAspectRatio="none"><path d="M 0 ${topGap} L ${bodyW} ${topGap} L ${bodyW} 0 L ${w} ${h/2} L ${bodyW} ${h} L ${bodyW} ${topGap + bodyH} L 0 ${topGap + bodyH} Z" fill="#4472C4" stroke="#000" stroke-width="1.5"/></svg>`;
  },
  star(w, h, points = 5) {
    const cx = w / 2, cy = h / 2, outerR = Math.min(w, h) / 2, innerR = outerR * 0.4;
    let pts = [];
    for (let i = 0; i < points * 2; i++) {
      const angle = (i * Math.PI) / points - Math.PI / 2;
      const r = i % 2 === 0 ? outerR : innerR;
      pts.push((cx + r * Math.cos(angle)).toFixed(1) + ',' + (cy + r * Math.sin(angle)).toFixed(1));
    }
    return `<svg viewBox="0 0 ${w} ${h}" preserveAspectRatio="none"><polygon points="${pts.join(' ')}" fill="#4472C4" stroke="#000" stroke-width="1.5"/></svg>`;
  },
  callout(w, h, type = 'speech') {
    // Simple speech bubble: rect with a tail polygon
    const tailSize = Math.min(w, h) * 0.2;
    if (type === 'speech') {
      return `<svg viewBox="0 0 ${w} ${h}" preserveAspectRatio="none"><rect width="${w - tailSize}" height="${h - tailSize}" fill="#4472C4" stroke="#000" stroke-width="1.5" rx="4"/><polygon points="${w - tailSize * 0.6},${h - tailSize} ${w - tailSize},${h} ${w},${h - tailSize}" fill="#4472C4" stroke="#000" stroke-width="1.5"/></svg>`;
    } else if (type === 'thought') {
      // Thought bubble: rounded rect + circles for the tail
      return `<svg viewBox="0 0 ${w} ${h}" preserveAspectRatio="none"><rect width="${w * 0.85}" height="${h * 0.8}" fill="#4472C4" stroke="#000" stroke-width="1.5" rx="8"/><circle cx="${w * 0.75}" cy="${h * 0.85}" r="${tailSize * 0.5}" fill="#4472C4" stroke="#000" stroke-width="1.5"/><circle cx="${w * 0.65}" cy="${h * 0.95}" r="${tailSize * 0.35}" fill="#4472C4" stroke="#000" stroke-width="1.5"/></svg>`;
    }
  },
};

H.shapes = (c, node) => shapesMenu(node);

function shapesMenu(node) {
  WC.flyout(node, (fly) => {
    fly.appendChild(WC.flyHeader('Shapes'));
    for (const [catName, shapes] of Object.entries(SHAPES)) {
      const it = WC.flyItem(catName, {});
      const chev = el('span', { class: 'caret', html: WC.icon('chevron_down', 8), style: { marginLeft: 'auto', transform: 'rotate(-90deg)' } });
      it.appendChild(chev);
      it.addEventListener('click', () => showShapeCategory(catName, shapes, node));
      fly.appendChild(it);
    }
  });
}

function showShapeCategory(catName, shapes, anchorNode) {
  WC.flyout(anchorNode, (fly) => {
    fly.appendChild(WC.flyHeader(catName));
    const grid = el('div', { style: { display: 'grid', gridTemplateColumns: 'repeat(4, 50px)', gap: '4px', padding: '8px' } });
    for (const [shapeId, config] of Object.entries(shapes)) {
      const preview = el('div', {
        title: config.label,
        style: {
          width: '48px', height: '48px', border: '1px solid #ddd', display: 'flex', alignItems: 'center',
          justifyContent: 'center', cursor: 'pointer', background: '#f5f5f5', borderRadius: '2px'
        }
      });
      const svg = config.gen(40, 40);
      preview.innerHTML = svg;
      preview.addEventListener('click', () => { WC.closeFlyouts(); insertShape(shapeId, config); });
      grid.appendChild(preview);
    }
    fly.appendChild(grid);
  });
}

function insertShape(shapeId, config) {
  const w = config.dw || 150, h = config.dh || 100;
  const svgHtml = config.gen(w, h);
  const wrapperId = 'shape-' + Date.now() + '-' + Math.random().toString(36).slice(2);
  const shapeHtml = `<div class="shape-wrapper" id="${wrapperId}" data-shape-id="${shapeId}" contenteditable="false" style="display:inline-block;width:${w}px;height:${h}px;position:relative;margin:4px;border:1px solid #999;user-select:none;cursor:move;">${svgHtml}<div class="shape-resize-handle" style="position:absolute;bottom:-4px;right:-4px;width:12px;height:12px;background:#4472C4;border:1px solid #fff;border-radius:50%;cursor:se-resize;opacity:0;transition:opacity .2s;"></div></div>&nbsp;`;
  E().insertHTML(shapeHtml);
  setTimeout(() => { attachShapeHandlers(wrapperId); }, 0);
}

function attachShapeHandlers(wrapperId) {
  const wrapper = document.getElementById(wrapperId);
  if (!wrapper) return;
  const handle = wrapper.querySelector('.shape-resize-handle');
  let isResizing = false, startX, startY, startW, startH;

  wrapper.addEventListener('mouseenter', () => { if (!isResizing) handle.style.opacity = '1'; });
  wrapper.addEventListener('mouseleave', () => { if (!isResizing) handle.style.opacity = '0'; });
  wrapper.addEventListener('click', (e) => { e.stopPropagation(); wrapper.classList.add('selected'); wrapper.style.borderColor = '#0078D4'; });
  wrapper.addEventListener('dblclick', (e) => {
    e.stopPropagation();
    const svg = wrapper.querySelector('svg');
    WC.flyout(wrapper, (fly) => {
      fly.appendChild(WC.colorPalette((color) => {
        if (color !== null) {
          const fillEls = svg.querySelectorAll('[fill]');
          fillEls.forEach((el2) => { if (el2.getAttribute('fill') !== 'none') el2.setAttribute('fill', color); });
          wrapper.dataset.fill = color;
        }
      }, { noColor: true, autoLabel: 'Default' }));
    });
  });

  handle.addEventListener('mousedown', (e) => {
    e.stopPropagation();
    isResizing = true;
    startX = e.clientX; startY = e.clientY;
    startW = wrapper.offsetWidth; startH = wrapper.offsetHeight;
    const onMove = (me) => {
      const dX = me.clientX - startX, dY = me.clientY - startY;
      let newW = Math.max(40, startW + dX);
      let newH = Math.max(30, startH + dY);
      if (me.shiftKey) { newH = (newW * startH) / startW; } // preserve aspect
      wrapper.style.width = newW + 'px';
      wrapper.style.height = newH + 'px';
    };
    const onUp = () => {
      isResizing = false;
      document.removeEventListener('mousemove', onMove);
      document.removeEventListener('mouseup', onUp);
      E().dirty = true; E().repaginate(); E().updateStatus();
    };
    document.addEventListener('mousemove', onMove);
    document.addEventListener('mouseup', onUp);
  });

  document.addEventListener('click', (e) => {
    if (!wrapper.contains(e.target) && !e.target.closest('[data-fly-anchor]')) {
      wrapper.classList.remove('selected');
      wrapper.style.borderColor = '#999';
    }
  });

  wrapper.addEventListener('keydown', (e) => {
    if (e.key === 'Delete' || e.key === 'Backspace') {
      e.preventDefault();
      wrapper.remove();
      E().dirty = true; E().repaginate(); E().updateStatus();
    }
  });
}
```

ALTERNATIVE: If you prefer a dialog-based shapes gallery (like Insert Table) instead of a nested flyout, create D.shapes in dialogs.js with a similar grid layout, listing all shapes. The insertion logic remains the same.

## 1. SCREENSHOT (Feasible: Yes, real working feature)

### Overview
Use Electron's `desktopCapturer` API to grab screen regions or windows. Implement two modes: "Available Windows" (list open windows to select one) and "Screen Clipping" (draw a rectangle to capture).

### Renderer Handler (`commands.js`)
```javascript
H.screenshot = (c, node) => WC.Dialogs.screenshot();
```

### Dialog Implementation (`dialogs.js` - new `D.screenshot`)
- Opens a dropdown menu with two items: "Available Windows" and "Screen Clipping"
- "Available Windows": calls `wordAPI.screenshotWindow()` to list windows; user picks one; inserts as `<img>` via captured base64
- "Screen Clipping": calls `wordAPI.screenshotRegion()` to enter screenshot mode (renderer overlays a transparent full-screen div with crosshair cursor, user drags to select region)

### Main Process IPC Handlers (`main.js`)

```javascript
// Requires: const { desktopCapturer } = require('electron');

ipcMain.handle('screenshot:windows', async () => {
  try {
    const sources = await desktopCapturer.getSources({ types: ['window', 'screen'] });
    return sources.map(s => ({ 
      id: s.id, 
      name: s.name, 
      thumbnail: s.thumbnail.toDataURL() // small preview
    }));
  } catch (e) {
    return { error: String(e) };
  }
});

ipcMain.handle('screenshot:capture-window', async (_evt, sourceId) => {
  try {
    const source = (await desktopCapturer.getSources({ types: ['window', 'screen'] }))
      .find(s => s.id === sourceId);
    if (!source) return { error: 'Window not found' };
    const img = await mainWindow.webContents.capturePage(source.getMediaSourceId());
    return { ok: true, dataUrl: img.toPNG().toString('base64') };
  } catch (e) {
    return { error: String(e) };
  }
});

ipcMain.handle('screenshot:capture-region', async (_evt, { x, y, width, height }) => {
  try {
    const img = await mainWindow.webContents.capturePage({ x, y, width, height });
    return { ok: true, dataUrl: img.toPNG().toString('base64') };
  } catch (e) {
    return { error: String(e) };
  }
});
```

### Preload Bridge (`preload.js`)
```javascript
screenshot: {
  getWindows: () => ipcRenderer.invoke('screenshot:windows'),
  captureWindow: (sourceId) => ipcRenderer.invoke('screenshot:capture-window', sourceId),
  captureRegion: (rect) => ipcRenderer.invoke('screenshot:capture-region', rect),
}
```

### Dialog Flow
1. User clicks Screenshot → dropdown with two items
2. Selects "Available Windows" → dialog showing thumbnails of open windows (from desktopCapturer). Click a window → captured and inserted as `<img src="data:image/png;base64,...">`.
3. OR selects "Screen Clipping" → full-screen overlay with crosshair; user drags to select region → captured and inserted.

